Connect-MgGraph -Scopes 'Policy.ReadWrite.Authorization'

# Enable the admin consent workflow
Update-MgPolicyAuthorizationPolicy -BodyParameter @{
    AdminConsentRequestPolicy = @{
        IsEnabled              = $true
        # Notify all admins when a request comes in
        NotifyReviewers        = $true
        RemindersEnabled       = $true
        # Request expires after N days if not reviewed
        RequestDurationInDays  = 30
        # Specific reviewers (optional — defaults to all admins)
        Reviewers = @(
            @{
                Query         = '/users/<admin-user-object-id>'
                QueryType     = 'MicrosoftGraph'
            }
        )
    }
}
Write-Host 'Admin consent workflow enabled.'

Connect-MgGraph -Scopes 'Policy.ReadWrite.Authorization'

# Read current authorization policy
$policy = Get-MgPolicyAuthorizationPolicy
Write-Host 'Current user consent setting:'
Write-Host $policy.PermissionGrantPolicyIdsAssignedToDefaultUserRole

# Option 1: Allow user consent for verified publisher apps with low-risk permissions only
# This is Microsoft's recommended setting for most organizations
Update-MgPolicyAuthorizationPolicy -BodyParameter @{
    PermissionGrantPolicyIdsAssignedToDefaultUserRole = @(
        'ManagePermissionGrantsForSelf.microsoft-user-default-low'
    )
}
Write-Host 'User consent limited to verified-publisher low-risk apps.'

# Option 2: Block all user consent (strictest — all consent requires admin)
Update-MgPolicyAuthorizationPolicy -BodyParameter @{
    PermissionGrantPolicyIdsAssignedToDefaultUserRole = @()
}
Write-Host 'User consent disabled — all consent requires admin approval.'

# Option 3: Allow all user consent (permissive — not recommended for production)
Update-MgPolicyAuthorizationPolicy -BodyParameter @{
    PermissionGrantPolicyIdsAssignedToDefaultUserRole = @(
        'ManagePermissionGrantsForSelf.microsoft-user-default-legacy'
    )
}
Write-Host 'User consent enabled for all apps (permissive mode).'

# Grant delegated permission admin consent for an app in the target tenant
resource "azuread_service_principal_delegated_permission_grant" "graph_consent" {
  service_principal_object_id          = azuread_service_principal.my_app.object_id
  resource_service_principal_object_id = data.azuread_service_principal.msgraph.object_id
  claim_values                         = ["User.Read", "openid", "profile", "offline_access"]
}

# Grant an application permission (app role assignment)
resource "azuread_app_role_assignment" "user_read_all" {
  app_role_id         = data.azuread_service_principal.msgraph.app_role_ids["User.Read.All"]
  principal_object_id = azuread_service_principal.my_app.object_id
  resource_object_id  = data.azuread_service_principal.msgraph.object_id
}

# Reference the Microsoft Graph service principal
data "azuread_service_principal" "msgraph" {
  client_id = "00000003-0000-0000-c000-000000000000"
}
